import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def pkg_map(projects):
    m = {}
    for p in projects:
        name = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                m[(name, pkg['id'])] = pkg['resolvedVersion']
    return m

b = pkg_map(baseline['projects'])
a = pkg_map(after['projects'])

print('CHANGES:')
for k in sorted(set(b) | set(a)):
    bv = b.get(k, 'N/A')
    av = a.get(k, 'N/A')
    if bv != av:
        print(f'  {k[0]:20s} {k[1]:40s} {bv:>10s} -> {av}')

print('UNCHANGED:')
for k in sorted(set(b) & set(a)):
    if b[k] == a[k]:
        print(f'  {k[0]:20s} {k[1]:40s} {b[k]}')
"

